return $input.all().map(item => {
  let raw = item.json.output;

  // Coerce non-string outputs (some models return an already-parsed object)
  if (raw && typeof raw === 'object') {
    return {
      json: {
        email_body: raw.body || "New updates are available.",
        subject: raw.subject || "Research Update"
      }
    };
  }
  raw = String(raw == null ? '' : raw);

  // Strip markdown code fences if the model added ```json ... ``` despite instructions
  raw = raw.trim().replace(/^```(?:json)?\s*/, '').replace(/\s*```$/, '');

  // Repair invalid JSON escapes. Valid JSON escapes after a backslash are
  // only: " \\ / b f n r t u. Free models sometimes emit stray backslashes
  // before other characters (e.g. \‑ before a non-breaking hyphen), which
  // makes JSON.parse throw "Unexpected token". Drop those stray backslashes.
  const sanitize = (s) => s.replace(/\\(?!["\\/bfnrtu])/g, '');

  const tryParse = (s) => {
    try { return JSON.parse(s); } catch (e) { return null; }
  };

  // Try raw, then sanitized, then a brace-extracted substring (raw + sanitized)
  let aiOutput = tryParse(raw) || tryParse(sanitize(raw));
  if (!aiOutput) {
    const match = raw.match(/\{[\s\S]*\}/);
    if (match) {
      aiOutput = tryParse(match[0]) || tryParse(sanitize(match[0]));
    }
  }

  if (!aiOutput || typeof aiOutput !== 'object') {
    aiOutput = {
      subject: "Research Update",
      body: "New updates are available. (Could not parse AI-generated content.)"
    };
  }

  return {
    json: {
      email_body: aiOutput.body || "New updates are available.",
      subject: aiOutput.subject || "Research Update"
    }
  };
});
